  // Reset flip state when item changes
  useEffect(() => {
    setIsFlipped(false);
  }, [item.id]);

  const handleFlip = () => setIsFlipped(!isFlipped);

  const handleAudioClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    onPlayAudio(item.english);
  };

  return (
    <div className="w-full max-w-lg mx-auto h-80 perspective-1000 relative mb-8">
      <div
        className={`relative w-full h-full text-center transition-transform duration-500 transform-style-3d cursor-pointer ${
          isFlipped ? 'rotate-y-180' : ''
