        onClick={handleFlip}
      >
        {/* Front (English) */}
        <div className="absolute w-full h-full bg-white rounded-2xl shadow-xl border border-gray-100 flex flex-col items-center justify-center p-8 backface-hidden">
          <span className="inline-block px-3 py-1 bg-blue-100 text-blue-800 text-xs font-semibold rounded-full mb-4 uppercase tracking-wide">
            {item.type}
