          <p className="text-gray-400 text-sm absolute bottom-4">Tap to see meaning</p>
        </div>

        {/* Back (Chinese) */}
        <div className="absolute w-full h-full bg-slate-800 rounded-2xl shadow-xl flex flex-col items-center justify-center p-8 backface-hidden rotate-y-180">
