        >
          Forgot
        </button>
        <button
          onClick={() => onResult(true)}
          className="flex-1 bg-emerald-500 hover:bg-emerald-600 text-white font-bold py-3 px-6 rounded-lg shadow-lg transform transition active:scale-95"
        >
          Remembered
        </button>
      </div>
