const generateId = () => Math.random().toString(36).substr(2, 9);

// Reduced to a single instruction card so the user knows they need to add their own data
export const DEFAULT_STUDY_DATA: StudyItem[] = [
  {
    id: generateId(),
    english: "Welcome to Phrase Master",
    chinese: "欢迎使用。请复制您的PDF内容到下方输入框以生成专属卡片。",
    type: "phrase",
    example: "Please paste your PDF content below to get started.",
    stage: 0,
    nextReviewDate: Date.now(),
    easeFactor: 2.5
  }
];

// Ebbinghaus Intervals in minutes/hours converted to milliseconds
export const INTERVALS = [
  0,
  5 * 60 * 1000,
  30 * 60 * 1000,
  12 * 60 * 60 * 1000,
  24 * 60 * 60 * 1000,
  2 * 24 * 60 * 60 * 1000,
  4 * 24 * 60 * 60 * 1000,
  7 * 24 * 60 * 60 * 1000,
  15 * 24 * 60 * 60 * 1000,
];

