                </div>
             )}
          </div>
        )}

        {mode === StudyMode.LIST && (
            <div className="w-full flex justify-center p-4 h-full">
                <VocabularyList items={studyData} onBack={() => setMode(StudyMode.DASHBOARD)} onPlayAudio={handlePlayAudio} onDelete={handleDeleteItem} />
            </div>
        )}
      </main>
    </div>
  );
}

