      alert(`Successfully added ${newItems.length} new items to ${groupName}!`);
    } catch (error) {
      console.error(error);
      alert("Failed to process content. Please ensure your API Key is valid.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handlePlayAudio = (text: string) => {
    playAudio(text);
  };

